---
import { cn } from "@/lib/utils"
import { Button } from "@/components/ui/button"
import { Section, SectionContainer } from "@/components/ui/section"

type Props = {
  class?: string
  title: string
  description: string
  buttons?: {
    label: string
    href: string
    variant?: "default" | "outline" | "secondary" | "ghost"
  }[]
}

const { class: className, title, description, buttons } = Astro.props
---

<Section
  variant="floating"
  class={cn("border-primary/20 shadow-none", className)}
>
  <SectionContainer
    class="before:from-primary/20 relative items-center before:absolute before:top-full before:left-1/2 before:-z-10 before:h-[200%] before:w-full before:-translate-x-1/2 before:rounded-full before:bg-gradient-to-b before:to-transparent before:blur-3xl"
  >
    <div class="flex max-w-2xl flex-col items-center gap-5 text-center">
      <h2
        class="text-foreground text-3xl leading-[1.1] font-semibold tracking-tight text-balance sm:text-4xl"
      >
        {title}
      </h2>
      <p class="text-muted-foreground text-lg leading-relaxed text-balance">
        {description}
      </p>
    </div>
    {
      buttons?.length && (
        <div class="flex flex-wrap justify-center gap-3">
          {buttons.map(({ href, label, ...button }, index) => (
            <Button
              as="a"
              href={href}
              size="lg"
              variant={button.variant ?? (index === 0 ? "default" : "outline")}
              {...button}
            >
              {label}
            </Button>
          ))}
        </div>
      )
    }
  </SectionContainer>
</Section>
